EE,wBAAA,CAAA,gBAAA","sourcesContent":["\n/**\n * 【为什么用 scoped】\n *   这些 CSS 会被 Vue 自动加上 data-v-xxx 哈希（如 .lh-fab[data-v-7ba5bd90]），\n *   不会影响酒馆原有的任何样式，反过来酒馆样式也不会影响我们的悬浮窗。\n *\n * 【为什么用 lang=\"scss\"】\n *   项目模板用的就是 scss，虽然这份代码没用到 scss 特性（嵌套/变量/mixin），\n *   但保持一致更好。将来你想用 & 嵌套写 .lh-fab { &:hover {...} } 也方便。\n */\n\n/* ── 悬浮球 ── */\n.lh-fab {\n  position: fixed;\n  width: 46px;\n  height: 46px;\n  border-radius: 50%;\n  background: #1b1030;\n  border: 1px solid rgba(167, 139, 250, 0.4);\n  color: #c4b5fd;\n  font-size: 22px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  cursor: grab;\n  user-select: none;\n  touch-action: none;\n  z-index: 100000;\n  box-shadow: 0 0 16px rgba(167, 139, 250, 0.35), 0 3px 12px rgba(0, 0, 0, 0.5);\n  transition: filter 0.15s, box-shadow 0.2s;\n\n  &:hover {\n    filter: brightness(1.2);\n    box-shadow: 0 0 26px rgba(167, 139, 250, 0.55);\n  }\n\n  &.is-dragging {\n    cursor: grabbing;\n  }\n}\n\n/* ── 面板 ── */\n/* left/top 由 :style 动态设置，这里只定义固定样式 */\n.lh-panel {\n  position: fixed;\n  width: 280px;\n  background: #120c1f;\n  border: 1px solid rgba(167, 139, 250, 0.3);\n  border-radius: 14px;\n  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.6);\n  z-index: 100001;\n  display: flex;\n  flex-direction: column;\n  overflow: hidden;\n  color: #e9e3ff;\n  font-family: 'Segoe UI', system-ui, sans-serif;\n}\n\n/* ── 标题栏（可拖动面板）── */\n.lh-head {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 8px 12px;\n  font-size: 13px;\n  border-bottom: 1px solid rgba(167, 139, 250, 0.15);\n  cursor: move;\n  user-select: none;\n\n  &.is-dragging {\n    cursor: grabbing;\n  }\n}\n\n.lh-close {\n  cursor: pointer;\n  width: 22px;\n  height: 22px;\n  line-height: 22px;\n  text-align: center;\n  border-radius: 6px;\n  color: #c4b5fd;\n\n  &:hover {\n    background: rgba(167, 139, 250, 0.2);\n  }\n}\n\n/* ── 【任务3】分类标签栏 ── */\n.lh-categories {\n  display: flex;\n  gap: 4px;\n  padding: 6px 10px;\n  border-bottom: 1px solid rgba(167, 139, 250, 0.15);\n  flex-wrap: wrap;\n}\n\n.lh-cat-tab {\n  flex: 1;\n  min-width: 48px;\n  padding: 4px 0;\n  font-size: 12px;\n  text-align: center;\n  cursor: pointer;\n  border-radius: 6px;\n  color: rgba(255, 255, 255, 0.5);\n  transition: background 0.15s, color 0.15s;\n\n  &:hover {\n    color: #c4b5fd;\n    background: rgba(167, 139, 250, 0.1);\n  }\n\n  &.active {\n    color: #e9e3ff;\n    background: rgba(167, 139, 250, 0.15);\n    font-weight: 600;\n  }\n}\n\n/* ── 立绘大图 ── */\n.lh-img-wrap {\n  width: 100%;\n  aspect-ratio: 2 / 3;\n  background: #0a0712;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  overflow: hidden;\n}\n\n.lh-img {\n  max-width: 100%;\n  max-height: 100%;\n  object-fit: contain;\n  display: block;\n}\n\n/* ── 切图按钮排 ── */\n.lh-btns {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 6px;\n  padding: 10px;\n}\n\n.lh-btn {\n  flex: 1 1 auto;\n  min-width: 56px;\n  padding: 6px 10px;\n  font-size: 12px;\n  text-align: center;\n  cursor: pointer;\n  border-radius: 8px;\n  border: 1px solid rgba(167, 139, 250, 0.25);\n  background: rgba(167, 139, 250, 0.08);\n  color: #d6ccff;\n  transition: background 0.15s, border-color 0.15s;\n\n  &:hover {\n    background: rgba(167, 139, 250, 0.2);\n  }\n\n  &.active {\n    background: #a78bfa;\n    border-color: #a78bfa;\n    color: #1b1030;\n    font-weight: 600;\n  }\n}\n\n/* ── 拖动时禁止全页选择文字 ── */\n.lh-fab.is-dragging *,\n.lh-panel-dragging * {\n  user-select: none;\n}\n"],"sourceRoot":""}]);
